#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_POINTS 2000
#define MAX_HULL_SIZE 2000
// Structure to represent a point
typedef struct {
    int x, y;
} Point;
// Function to calculate the orientation of three points
int orientation(Point p, Point q, Point r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // Collinear
    return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
}
// Function to calculate the convex hull
void convexHull(Point points[], int n, Point hull[], int *hullSize) {
    if (n < 3) {
        *hullSize = n;
        for (int i = 0; i < n; i++) hull[i] = points[i];
        return;
    }
    int l = 0;
    for (int i = 1; i < n; i++)
        if (points[i].x < points[l].x)
            l = i;
    int p = l, q;
    do {
        hull[*hullSize] = points[p];
        (*hullSize)++;
        q = (p + 1) % n;
        for (int i = 0; i < n; i++)
            if (orientation(points[p], points[i], points[q]) == 2)
                q = i;
        p = q;
    } while (p != l);
}
// Function to check if two convex hulls are separable
int areHullsSeparable(Point redHull[], int redHullSize, Point blueHull[], int blueHullSize) {
    for (int i = 0; i < redHullSize; i++) {
        Point p1 = redHull[i], p2 = redHull[(i + 1) % redHullSize];
        for (int j = 0; j < blueHullSize; j++) {
            Point p3 = blueHull[j], p4 = blueHull[(j + 1) % blueHullSize];
            if (orientation(p1, p2, p3) * orientation(p1, p2, p4) < 0)
                return 0;
        }
    }
    return 1;
}
// Function to solve the problem
void solve() {
    int n, m;
    scanf("%d %d", &n, &m);
    Point redPoints[n], bluePoints[m];
    for (int i = 0; i < n; i++) scanf("%d %d", &redPoints[i].x, &redPoints[i].y);
    for (int i = 0; i < m; i++) scanf("%d %d", &bluePoints[i].x, &bluePoints[i].y);
    Point redHull[MAX_HULL_SIZE], blueHull[MAX_HULL_SIZE];
    int redHullSize, blueHullSize;
    convexHull(redPoints, n, redHull, &redHullSize);
    convexHull(bluePoints, m, blueHull, &blueHullSize);
    if (areHullsSeparable(redHull, redHullSize, blueHull, blueHullSize)) {
        printf("0\n");
        return;
    }
    int minDeletions = n + m;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            Point newRedPoints[n - 1], newBluePoints[m - 1];
            int k = 0, l = 0;
            for (int p = 0; p < n; p++) if (p != i) newRedPoints[k++] = redPoints[p];
            for (int p = 0; p < m; p++) if (p != j) newBluePoints[l++] = bluePoints[p];
            Point newRedHull[MAX_HULL_SIZE], newBlueHull[MAX_HULL_SIZE];
            int newRedHullSize, newBlueHullSize;
            convexHull(newRedPoints, n - 1, newRedHull, &newRedHullSize);
            convexHull(newBluePoints, m - 1, newBlueHull, &newBlueHullSize);
            if (areHullsSeparable(newRedHull, newRedHullSize, newBlueHull, newBlueHullSize))
                minDeletions = 2;
        }
    }
    printf("%d\n", minDeletions);
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) solve();
    return 0;
}

