#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
// Structure to represent a point
struct Point {
    int x, y;
};
// Function to calculate the orientation of three points
int orientation(Point p, Point q, Point r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // Collinear
    return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
}
// Function to calculate the convex hull
void convexHull(vector<Point> points, vector<Point> &hull) {
    if (points.size() < 3) {
        hull = points;
        return;
    }
    int l = 0;
    for (int i = 1; i < points.size(); i++)
        if (points[i].x < points[l].x)
            l = i;
    int p = l, q;
    do {
        hull.push_back(points[p]);
        q = (p + 1) % points.size();
        for (int i = 0; i < points.size(); i++)
            if (orientation(points[p], points[i], points[q]) == 2)
                q = i;
        p = q;
    } while (p != l);
}
// Function to check if two convex hulls are separable
int areHullsSeparable(vector<Point> redHull, vector<Point> blueHull) {
    for (int i = 0; i < redHull.size(); i++) {
        Point p1 = redHull[i], p2 = redHull[(i + 1) % redHull.size()];
        for (int j = 0; j < blueHull.size(); j++) {
            Point p3 = blueHull[j], p4 = blueHull[(j + 1) % blueHull.size()];
            if (orientation(p1, p2, p3) * orientation(p1, p2, p4) < 0)
                return 0;
        }
    }
    return 1;
}
// Function to solve the problem
void solve() {
    int n, m;
    cin >> n >> m;
    vector<Point> redPoints(n), bluePoints(m);
    for (int i = 0; i < n; i++) cin >> redPoints[i].x >> redPoints[i].y;
    for (int i = 0; i < m; i++) cin >> bluePoints[i].x >> bluePoints[i].y;
    vector<Point> redHull, blueHull;
    convexHull(redPoints, redHull);
    convexHull(bluePoints, blueHull);
    if (areHullsSeparable(redHull, blueHull)) {
        cout << 0 << endl;
        return;
    }
    int minDeletions = n + m;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            vector<Point> newRedPoints, newBluePoints;
            for (int p = 0; p < n; p++) if (p != i) newRedPoints.push_back(redPoints[p]);
            for (int p = 0; p < m; p++) if (p != j) newBluePoints.push_back(bluePoints[p]);
            vector<Point> newRedHull, newBlueHull;
            convexHull(newRedPoints, newRedHull);
            convexHull(newBluePoints, newBlueHull);
            if (areHullsSeparable(newRedHull, newBlueHull))
                minDeletions = 2;
        }
    }
    cout << minDeletions << endl;
}
int main() {
    int t;
    cin >> t;
    while (t--) solve();
    return 0;
}
